const express = require('express');
const { Client } = require('@elastic/elasticsearch');

const app = express();

app.use(express.json({ limit: '2mb' }));

const es = new Client({
  node: process.env.ELASTICSEARCH_NODE || 'http://localhost:9200',
  auth: process.env.ELASTICSEARCH_USERNAME
    ? { username: process.env.ELASTICSEARCH_USERNAME, password: process.env.ELASTICSEARCH_PASSWORD || '' }
    : undefined,
  tls: process.env.ELASTICSEARCH_TLS_REJECT_UNAUTHORIZED === 'false'
    ? { rejectUnauthorized: false }
    : undefined
});

app.post('/api/es/:index/_search', async (req, res) => {
  try {
    const index = req.params.index;
    const query = (req.body && req.body.query) || {};
    const result = await es.search({ index, body: query });
    res.status(200).json(result);
  } catch (err) {
    const statusCode = err?.meta?.statusCode || 500;
    res.status(statusCode).json({
      error: true,
      message: err?.message || 'Elasticsearch error',
      statusCode,
      details: err?.meta?.body || err?.meta || undefined
    });
  }
});

app.get('/health', async (_req, res) => {
  try {
    const info = await es.info();
    res.status(200).json({ ok: true, es: info });
  } catch (err) {
    res.status(500).json({ ok: false, error: err?.message || 'error' });
  }
});

const port = Number(process.env.PORT || 3000);
app.listen(port, () => {
  console.log(`Elasticsearch API listening on :${port}`);
});